// Parse Claude's JSON output safely
const raw = $input.first().json.text || $input.first().json.content || '';

let jobs = [];
try {
  const cleaned = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  jobs = JSON.parse(cleaned);
} catch (e) {
  // If parse fails, return empty so workflow ends gracefully
  jobs = [];
}

if (!Array.isArray(jobs) || jobs.length === 0) {
  return [{ json: { no_new_jobs: true } }];
}

return jobs.map(job => ({ json: job }));

// Get all seen job IDs from the Google Sheet
const seenRows = $('Read Seen Job IDs').all();
const seenIds = new Set(seenRows.map(r => r.json.job_id).filter(Boolean));

// Get current job from previous node
const job = $input.first().json;

// Check if this job is new
if (seenIds.has(job.job_id)) {
  return [{ json: { is_new: false, job } }];
}

return [{ json: { is_new: true, job } }];

// Merge job data with match scoring
const job = $('Is New Opportunity?').first().json.job;
const raw = $input.first().json.text || $input.first().json.content || '{}';

let score = {};
try {
  const cleaned = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  score = JSON.parse(cleaned);
} catch(e) {
  score = {
    match_score: 5,
    why_suitable: 'Could not parse scoring.',
    missing_skills: [],
    suggestions: 'Review manually.',
    recommended_action: 'Apply immediately'
  };
}

return [{ json: { ...job, ...score } }];

// No new jobs found — silent end
console.log('Career monitor ran. No new listings found at ' + new Date().toISOString());
return [];
